import anthropic

client = anthropic.Anthropic()

# Pattern: tiered safety based on action risk, preserving capability for low-risk actions
RISK_TIERS = {
    "low":    {"read_file", "list_files", "search_code"},   # no approval needed
    "medium": {"write_file", "append_file"},                 # async review within 1 min
    "high":   {"delete_file", "send_email", "db_write"},    # sync approval required
}

def classify_tool_risk(tool_name: str) -> str:
    for tier, tools in RISK_TIERS.items():
        if tool_name in tools:
            return tier
    return "high"  # unknown tools default to high risk


def tiered_execute(tool_name: str, tool_input: dict, require_sync_approval) -> str:
    """
    Execute a tool call with approval proportional to its risk tier.
    Low-risk calls execute immediately; high-risk require explicit approval.
    This preserves throughput for the 80% of calls that are low-risk.
    """
    tier = classify_tool_risk(tool_name)

    if tier == "low":
        pass  # execute immediately, no overhead
    elif tier == "medium":
        # Log for async review; continue execution
        print(f"[ASYNC REVIEW] {tool_name} queued for review")
    elif tier == "high":
        approved = require_sync_approval(tool_name, tool_input)
        if not approved:
            return f"Approval denied for {tool_name} — action not taken"

    # Execute (placeholder)
    return f"executed {tool_name}"
